from itertools import permutations

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape
    bg = int(grid[0, 0])

    # 1. Find connected components
    objs = get_objects(grid, bg)
    if not objs:
        return grid.tolist()

    # 2. Pad to max height, centered
    max_h = max(o.shape[0] for o in objs)
    padded = [pad_to_height(o, max_h, bg) for o in objs]
    n = len(padded)

    # 3. Find strict overlaps
    strict = {}
    for i in range(n):
        for j in range(n):
            if i != j:
                k = find_strict_overlap(padded[i], padded[j], bg)
                if k > 0:
                    strict[(i,j)] = k

    # 4. Find containment: if strict overlap A->B = width of B, B is contained in A
    contained = set()
    for (i,j), k in strict.items():
        if k == padded[j].shape[1]:
            contained.add(j)

    # 5. Non-contained objects
    active = [i for i in range(n) if i not in contained]

    # 6. Build chain using strict overlaps (excluding containments)
    active_strict = {}
    for (i,j), k in strict.items():
        if i in active and j in active and k < padded[j].shape[1]:
            active_strict[(i,j)] = k

    # Find chain: try all permutations, pick the one where all consecutive pairs have strict overlap
    best_chain = None
    for perm in permutations(active):
        valid = True
        for idx in range(len(perm)-1):
            if (perm[idx], perm[idx+1]) not in active_strict:
                valid = False
                break
        if valid:
            if best_chain is None:
                best_chain = perm

    if best_chain is None:
        # Fallback: just use active objects in order
        best_chain = tuple(active)

    # 7. Stitch chain using soft overlaps
    result = padded[best_chain[0]].copy()
    for idx in range(1, len(best_chain)):
        A_idx = best_chain[idx-1]
        B_idx = best_chain[idx]
        # But we need soft overlap between current result's right side and next object's left side
        # Actually, use soft overlap between the last added object and the next
        k = find_overlap(padded[A_idx], padded[B_idx], bg)
        if k == 0:
            k = 1  # minimum connection

        B = padded[B_idx]
        new_cols = B.shape[1] - k
        new_result = np.full((max_h, result.shape[1] + new_cols), bg)
        new_result[:, :result.shape[1]] = result

        # Merge overlap region
        overlap_start = result.shape[1] - k
        for r in range(max_h):
            for c in range(B.shape[1]):
                out_c = overlap_start + c
                if B[r, c] != bg:
                    new_result[r, out_c] = B[r, c]

        result = new_result

    return result.tolist()

# Test
for i, s in enumerate(train_samples):
    out = solve(s['input'])
    expected = s['output']
    match = out == expected
    print(f"Example {i}: {'PASS' if match else 'FAIL'}")
    if not match:
        print(f"  Expected: {expected}")
        print(f"  Got:      {out}")

