    H, W = grid.shape
    bg = int(grid[0, 0])

    objs_raw = flood_fill_objects(grid, bg)
    if not objs_raw:
        return grid.tolist()

    objs = []
    for cells in objs_raw:
        rows = [c[0] for c in cells]
        cols = [c[1] for c in cells]
        r0, r1 = min(rows), max(rows)
        c0, c1 = min(cols), max(cols)
        bbox = grid[r0:r1+1, c0:c1+1].copy()
        objs.append(bbox)

    n = len(objs)
    max_h = max(o.shape[0] for o in objs)
    padded = [pad_to_height(o, max_h, bg) for o in objs]

    # Find strict overlaps (horizontal: right of A matches left of B)
    strict = {}
    for i in range(n):
        for j in range(n):
            if i != j:
                k = find_strict_overlap(padded[i], padded[j], bg)
                if k > 0:
                    strict[(i,j)] = k

    # Find containments
    contained = set()
    for (i,j), k in strict.items():
        if k == padded[j].shape[1]:
            contained.add(j)

    active = [i for i in range(n) if i not in contained]

    # Build chain from strict overlaps (excluding containments)
    active_strict = {}
    for (i,j), k in strict.items():
        if i in active and j in active and k < padded[j].shape[1]:
            active_strict[(i,j)] = k

    # Find the longest chain using strict overlaps
    best_chain = None
    best_chain_len = 0

    for start in active:
        # BFS/DFS to find chains starting from 'start'
        stack = [(start, [start])]
        while stack:
            curr, path = stack.pop()
            if len(path) > best_chain_len:
                best_chain_len = len(path)
                best_chain = list(path)
            for next_node in active:
                if next_node not in path and (curr, next_node) in active_strict:
                    stack.append((next_node, path + [next_node]))

    # Also check soft overlaps to extend the chain
    if best_chain:
        # Try to extend at both ends using soft overlap
        for _ in range(n):
            extended = False
            # Extend right
            last = best_chain[-1]
            best_ext = None
            best_ext_score = 0
            for j in active:
                if j not in best_chain:
                    k = find_overlap(padded[last], padded[j], bg)
                    if k > best_ext_score:
                        best_ext = j
                        best_ext_score = k
            if best_ext is not None and best_ext_score > 0:
                best_chain.append(best_ext)
                extended = True

            # Extend left
            first = best_chain[0]
            best_ext = None
            best_ext_score = 0
            for j in active:
                if j not in best_chain:
                    k = find_overlap(padded[j], padded[first], bg)
                    if k > best_ext_score:
                        best_ext = j
                        best_ext_score = k
            if best_ext is not None and best_ext_score > 0:
                best_chain.insert(0, best_ext)
                extended = True

            if not extended:
                break

    if best_chain is None or len(best_chain) == 0:
        best_chain = [active[0]] if active else [0]

    # Build canvas from chain
    canvas = padded[best_chain[0]].copy()
    for idx in range(1, len(best_chain)):
        prev = best_chain[idx-1]
        curr = best_chain[idx]
        k = find_overlap(padded[prev], padded[curr], bg)
        if k == 0:
            k = find_strict_overlap(padded[prev], padded[curr], bg)
        if k == 0:
            k = 1  # minimum

        B = padded[curr]
        new_cols = B.shape[1] - k
        new_canvas = np.full((max_h, canvas.shape[1] + new_cols), bg)
        new_canvas[:, :canvas.shape[1]] = canvas
        overlap_start = canvas.shape[1] - k
        for r in range(max_h):
            for c in range(B.shape[1]):
