def find_best_semistrict_placement(canvas, obj, bg):
    """Find position where canvas non-bg cells in overlap region are all matched by obj.
    obj non-bg cells can go on canvas bg cells (extending).
    Canvas non-bg cells in overlap must match obj exactly.
    Returns (dr, dc, score) where score = number of matching non-bg cells."""
    ch, cw = canvas.shape
    oh, ow = obj.shape

    best = None
    for dr in range(-oh + 1, ch):
        for dc in range(-ow + 1, cw):
            score = 0
            valid = True

            for r in range(oh):
                for c in range(ow):
                    cr, cc = r + dr, c + dc
                    if 0 <= cr < ch and 0 <= cc < cw:
                        cv = canvas[cr, cc]
                        ov = obj[r, c]
                        if cv != bg:
                            # Canvas has non-bg: obj must match exactly
                            if ov != cv:
                                valid = False
                                break
                            else:
                                score += 1
                        # If canvas is bg: obj can be anything (bg or non-bg)
                if not valid:
                    break

            if valid and score > 0:
                # Check that obj adds new content
                total_nonbg = int(np.sum(obj != bg))
                # Score is matching canvas non-bg cells; total_nonbg includes new cells too
                if total_nonbg > score:  # Some new cells added
                    if best is None or score > best[2]:
                        best = (dr, dc, score)
    return best

