def compute_pairwise_offsets(objs, bg):
    """For each ordered pair (i,j), find the offset to place obj j on obj i."""
    n = len(objs)
    offsets = {}
    for i in range(n):
        for j in range(n):
            if i == j:
                continue
            result = find_best_placement(objs[i], objs[j], bg)
            if result:
                dr, dc, score = result
                offsets[(i,j)] = (dr, dc, score)
    return offsets

# Build graph with undirected edges (use best direction)
offsets = compute_pairwise_offsets(objs, bg)

# For each pair (i<j), pick the direction with higher score
edges = []
for i in range(len(objs)):
    for j in range(i+1, len(objs)):
        score_ij = offsets.get((i,j), (0,0,0))[2]
        score_ji = offsets.get((j,i), (0,0,0))[2]
        best_score = max(score_ij, score_ji)
        if best_score > 0:
            if score_ij >= score_ji:
                # j is placed on i: j at offset (dr, dc) relative to i
                dr, dc, _ = offsets[(i,j)]
                edges.append((best_score, i, j, dr, dc))
            else:
                # i is placed on j: i at offset (dr, dc) relative to j
                dr, dc, _ = offsets[(j,i)]
                edges.append((best_score, j, i, dr, dc))

# Sort edges by score descending (for maximum spanning tree)
