print("Edges sorted by score:")
for score, base, placed, dr, dc in edges:
    print(f"  Obj {placed} on Obj {base}: offset ({dr},{dc}), score {score}")

# Kruskal's MST (using highest score edges first)
parent = list(range(len(objs)))
def find(x):
    while parent[x] != x:
        parent[x] = parent[parent[x]]
        x = parent[x]
    return x

mst_edges = []
for score, base, placed, dr, dc in edges:
    if find(base) != find(placed):
        parent[find(base)] = find(placed)
        mst_edges.append((base, placed, dr, dc, score))
        print(f"MST edge: Obj {placed} on Obj {base}, offset ({dr},{dc}), score {score}")

# Determine global positions using MST
