    hA, wA = len(A), len(A[0])
    hB, wB = len(B), len(B[0])
    results = []

    for dr in range(-hB+1, hA):
        for dc in range(-wB+1, wA):
            score = 0.0
            conflict = False
            for rb in range(hB):
                ra = rb + dr
                if ra < 0 or ra >= hA:
                    continue
                for cb in range(wB):
                    ca = cb + dc
                    if ca < 0 or ca >= wA:
                        continue
                    va, vb = A[ra][ca], B[rb][cb]
                    if va != bg and vb != bg:
                        if va == vb:
