# Obj 0: NONE - can't be placed directly on Obj 4 with semi-strict.

# Let me now build a semi-strict greedy assembly:

def semistrict_greedy_assembly(objs, bg, cw):
    n = len(objs)
    largest = max(range(n), key=lambda i: len(objs[i])*len(objs[i][0]))

    placed = {largest: (0, 0)}
    remaining = set(range(n)) - {largest}

    while remaining:
        # Build current canvas
        all_pos = list(placed.items())
        min_r = min(p[0] for _, p in all_pos)
        min_c = min(p[1] for _, p in all_pos)
        max_r = max(p[0] + len(objs[i]) - 1 for i, p in all_pos)
        max_c = max(p[1] + len(objs[i][0]) - 1 for i, p in all_pos)

        # Extend canvas a bit to allow objects to be placed partially outside
        pad = max(max(len(o) for o in objs), max(len(o[0]) for o in objs))
        H = max_r - min_r + 1 + 2*pad
        W = max_c - min_c + 1 + 2*pad
        canvas = [[bg]*W for _ in range(H)]
        for idx, (gr, gc) in all_pos:
            r0 = gr - min_r + pad
            c0 = gc - min_c + pad
            for r in range(len(objs[idx])):
                for c in range(len(objs[idx][0])):
                    val = objs[idx][r][c]
                    if val != bg:
                        canvas[r0+r][c0+c] = val

        best = None
        for idx in remaining:
            ps = find_semistrict_2d_placements(canvas, objs[idx], bg, cw, H, W)
            if ps:
                dr, dc, score = ps[0]
                gr = min_r - pad + dr
                gc = min_c - pad + dc

                # Also check no conflicts with existing objects (soft check)
                conflict = False
                for qidx, (qr, qc) in placed.items():
                    for ri in range(len(objs[idx])):
                        if conflict: break
                        for ci in range(len(objs[idx][0])):
                            vi = objs[idx][ri][ci]
                            if vi == bg: continue
                            rq = gr + ri - qr
                            cq = gc + ci - qc
                            if 0 <= rq < len(objs[qidx]) and 0 <= cq < len(objs[qidx][0]):
                                vq = objs[qidx][rq][cq]
                                if vq != bg and vq != vi:
                                    conflict = True
                                    break

                if not conflict and (best is None or score > best[0]):
                    best = (score, idx, gr, gc)

        if best is None:
            # Fallback to soft matching
            for idx in remaining:
                for pidx, (pr, pc) in placed.items():
                    ps = find_best_2d_placements_weighted(objs[pidx], objs[idx], bg, cw)
                    for dr, dc, score in ps[:3]:
                        gr, gc = pr + dr, pc + dc
                        conflict = False
                        for qidx, (qr, qc) in placed.items():
                            for ri in range(len(objs[idx])):
