                                for ci in range(len(objs[idx][0])):
                                    vi = objs[idx][ri][ci]
                                    if vi == bg: continue
                                    rq = gr + ri - qr
                                    cq = gc + ci - qc
                                    if 0 <= rq < len(objs[qidx]) and 0 <= cq < len(objs[qidx][0]):
                                        vq = objs[qidx][rq][cq]
                                        if vq != bg and vq != vi:
                                            conflict = True
                                            break
                        if not conflict and (best is None or score > best[0]):
                            best = (score, idx, gr, gc)
            if best is None:
